```cpp
#include <unistd.h>
#include <stdio.h>
#include <sys/types.h>
#include <sys/wait.h>

int main() {
    int fd[2];  // File descriptor for pipe
    pid_t pid;

    // Create a pipe
    if (pipe(fd) == -1) {
        perror("pipe");
        return 1;
    }

    // Fork a child process
    pid = fork();
    if (pid == -1) {
        perror("fork");
        return 1;
    }

    // Child process
    if (pid == 0) {
        // Close unused half of the pipe
        close(fd[1]);  // Close write end in child
        close(fd[0]);  // Close read end in child

        // Redirect stdin and stdout to the pipe's read end
        dup2(fd[0], STDIN_FILENO);
        dup2(fd[0], STDOUT_FILENO);

        // Execute a new program, e.g., "cat"
        if (execlp("cat", "cat", (char*)0) == -1) {
            perror("execlp");
            return 1;
        }
    }
    // Parent process
    else {
        // Close unused half of the pipe
        close(fd[0]);  // Close read end in parent
        close(fd[1]);  // Close write end in parent

        // Write to the pipe (simulating input)
        const char* message = "Hello, from the parent process!";
        write(fd[1], message, strlen(message) + 1);

        // Wait for the child to finish
        wait(NULL);
    }

    return 0;
}
```

This code snippet demonstrates how to create a pipe, fork a child process, and redirect the child's standard input and output to the read end of the pipe. The parent process writes a message to the pipe, which the child process reads and prints.
